public class CastCheck {
    static class Animal { String sound() { return "..."; } }
    static class Dog extends Animal { @Override String sound() { return "woof"; } }
    static class Cat extends Animal { @Override String sound() { return "meow"; } }
    public static void main(String[] args) {
        Animal[] pets = {new Dog(), new Cat(), new Dog()};
        for (Animal a : pets) {
            if (a instanceof Dog) System.out.println("Dog:" + a.sound());
            else System.out.println("Other:" + a.sound());
        }
    }
}
